// n8n HTTP Request already splits a JSON array response into individual items.
// Each item here is already one task — just pass them through.
const items = $input.all();
if (!items || items.length === 0) {
  console.log('[RevenueRadar] No pending tasks found.');
  return [];
}
console.log(`[RevenueRadar] Processing ${items.length} pending task(s).`);
return items.map(item => ({ json: item.json }));

// Transform SerpAPI response to match our workflow format
const items = $input.all();
const results = [];

for (const item of items) {
  const serpData = item.json;

  // Extract shopping results
  const shoppingResults = serpData.shopping_results || [];

  // Extract all prices (convert to PKR if needed)
  const prices = shoppingResults
    .map(product => {
      let price = product.extracted_price || product.price;

      // If price is a string, try to extract number
      if (typeof price === 'string') {
        price = parseFloat(price.replace(/[^0-9.]/g, ''));
      }

      return price;
    })
    .filter(price => price && price > 0 && price < 10000000);

  // Extract product titles and links
  const titles = shoppingResults.map(p => p.title).filter(t => t);
  const links = shoppingResults.map(p => p.link).filter(l => l);
  const sources = shoppingResults.map(p => p.source).filter(s => s);

  // Calculate statistics
  const priceStats = {
    min: prices.length > 0 ? Math.min(...prices) : 0,
    max: prices.length > 0 ? Math.max(...prices) : 0,
    avg: prices.length > 0 ? Math.round(prices.reduce((a,b) => a+b) / prices.length) : 0,
    count: prices.length
  };

  // Get original task data from the previous node
  const originalTask = item.json.original_task || {};

  // Build structured output for AI analysis
  results.push({
    json: {
      // Preserve original task info
      original_task: originalTask,

      // Scraped data from SerpAPI
      prices_found: prices,
      min_price_pkr: priceStats.min,
      max_price_pkr: priceStats.max,
      avg_price_pkr: priceStats.avg,
      price_count: priceStats.count,
      price_variance_percent: priceStats.max > 0 ? Math.round(((priceStats.max - priceStats.min) / priceStats.min) * 100) : 0,

      // Product information
      product_titles: titles.slice(0, 15),
      product_sources: sources.slice(0, 10),
      evidence_links: links.slice(0, 5),

      // Data quality indicators
      data_quality: prices.length >= 10 ? 'excellent' : 
                    prices.length >= 5 ? 'good' : 
                    prices.length >= 3 ? 'moderate' : 'poor',
      sources_analyzed: shoppingResults.length,

      // Full context summary for AI
      research_summary: `Analyzed ${shoppingResults.length} products for "${originalTask.Topic}" in ${originalTask.Region}. Found ${prices.length} valid prices ranging from PKR ${priceStats.min} to PKR ${priceStats.max}.`
    }
  });
}

return results;

