// Parse AI response and calculate opportunity score - SIMPLE robust parsing
const item = $input.first();
let analysis;

try {
  // Get the raw AI text
  let text = item.json.text || item.json.output || '';

  // Remove markdown code fences ONLY (do not mangle the JSON itself)
  text = text.replace(/```json/gi, '').replace(/```/g, '').trim();

  // Extract the JSON object between the first { and last }
  const jsonStart = text.indexOf('{');
  const jsonEnd = text.lastIndexOf('}');
  if (jsonStart !== -1 && jsonEnd !== -1) {
    text = text.substring(jsonStart, jsonEnd + 1);
  }

  // Parse directly - the AI returns valid JSON, no cleanup needed
  analysis = JSON.parse(text);

} catch (error) {
  console.error('JSON Parse Error:', error.message);
  analysis = {
    verified_trend: "Data collected but AI response format error - retry needed",
    pricing_gap: {
      competitor_range: "Unable to parse",
      recommended_position: "N/A",
      opportunity: "Insufficient data quality"
    },
    feature_insights: ["AI analysis failed to parse - retry recommended"],
    confidence_score: 0,
    confidence_rationale: "JSON parsing error: " + error.message,
    evidence_links: [],
    data_summary: {
      sources_analyzed: 0,
      price_points_found: 0,
      avg_price_pkr: 0,
      price_variance_percent: 0
    },
    error: error.message,
    raw_response: (item.json.text || item.json.output || '').substring(0, 500)
  };
}

// Ensure all required fields exist
analysis.verified_trend = analysis.verified_trend || "No trend identified";
analysis.pricing_gap = analysis.pricing_gap || {
  competitor_range: "N/A",
  recommended_position: "N/A",
  opportunity: "N/A"
};
analysis.feature_insights = analysis.feature_insights || [];
analysis.confidence_score = analysis.confidence_score || 0;
analysis.confidence_rationale = analysis.confidence_rationale || "No rationale provided";
analysis.evidence_links = analysis.evidence_links || [];
analysis.data_summary = analysis.data_summary || {
  sources_analyzed: 0,
  price_points_found: 0,
  avg_price_pkr: 0
};

// Calculate opportunity score (0-100)
let opportunityScore = 0;
if (analysis.confidence_score) {
  opportunityScore += (analysis.confidence_score / 100) * 40;
  if (analysis.pricing_gap && analysis.pricing_gap.competitor_range) {
    const range = String(analysis.pricing_gap.competitor_range).match(/([0-9,]+)/g);
    if (range && range.length >= 2) {
      const min = parseInt(range[0].replace(/,/g, ''));
      const max = parseInt(range[1].replace(/,/g, ''));
      const gapPercent = min > 0 ? ((max - min) / min) * 100 : 0;
      if (gapPercent > 50) opportunityScore += 30;
      else if (gapPercent > 25) opportunityScore += 20;
      else opportunityScore += 10;
    }
  }
  const insightCount = analysis.feature_insights.length || 0;
  opportunityScore += Math.min(insightCount * 10, 30);
}
analysis.opportunity_score = Math.round(Math.min(opportunityScore, 100));
analysis.status = analysis.confidence_score >= 50 ? 'approved' : 'needs_retry';
analysis.processed_at = new Date().toISOString();

// Preserve original task data
try {
  analysis.original_task = $('Transform SerpAPI Data').first().json.original_task;
} catch (e) {
  analysis.original_task = {
    id: null,
    Topic: "Unknown",
    Region: "Unknown",
    'Target Competitors': "",
    'Retry Count': 0
  };
}

return [{ json: analysis }];

